        val code =
            """
            import android.annotation.SuppressLint
            import android.content.Context

            val Context.adsDelegateFactory @SuppressLint("WrongConstant") get() =
                applicationContext.getSystemService(SYSTEM_SERVICE_AD_DELEGATE_FACTORY) as AdsDelegateFactory
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an extension property with private modifier on getter then do not emit`() {
        val code =
            """
            import android.content.Context

            val Context.adsDelegateFactory private get() =
                applicationContext.getSystemService(SYSTEM_SERVICE_AD_DELEGATE_FACTORY) as AdsDelegateFactory
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a top-level property with annotation on getter then do not emit`() {
        val code =
            """
            import android.annotation.SuppressLint

            val foo @SuppressLint("WrongConstant") get() = "bar"
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a class property with annotation on getter then do not emit`() {
        val code =
            """
            import android.annotation.SuppressLint

            class Foo {
                val bar @SuppressLint("WrongConstant") get() = "baz"
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an object property with annotation on getter then do not emit`() {
        val code =
            """
            import android.annotation.SuppressLint

            object Foo {
                val bar @SuppressLint("WrongConstant") get() = "baz"
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a companion object property with annotation on getter then do not emit`() {
        val code =
            """
            import android.annotation.SuppressLint

            class Foo {
                companion object {
                    val bar @SuppressLint("WrongConstant") get() = "baz"
                }
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }
}
