            class Foo {
                val bar @SuppressLint("WrongConstant") private get() = "baz"
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given property with getter but no annotation should follow naming rules`() {
        val code =
            """
            val FOO_BAR get() = "bar"
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

