    fun `Given property with getter on new line with annotation should not emit`() {
        val code =
            """
            import android.annotation.SuppressLint

            val foo
                @SuppressLint("test")
                get() = "bar"
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }
}
